  const avgEvents = (seed % 4 + 1.2).toFixed(1);
  const confidence = 82 + seed % 14;
  const severityTrend = seed % 3 === 0 ? "Increasing (+14% vs 2024)" : seed % 3 === 1 ? "Stable (0% vs 2024)" : "Decreasing (-6% vs 2024)";
